//! HTML entity escaping used by the web layer.
//!
//! Observed escape set (from oracle output): the five characters
//! `& < > " '` map to `&amp; &lt; &gt; &quot; &#39;` respectively; every other
//! byte (including all non-ASCII UTF-8, e.g. the logic operators the prover
//! emits) passes through unchanged. Escaping is applied left-to-right in a
//! single pass, and `&` is handled first so already-produced entities are not
//! double-escaped.
//!
//! Witnesses:
//!   `'` -> `&#39;`   (the "'smart' heuristic" comment in proof-method pages)
//!   `<`,`>` -> `&lt;`,`&gt;`   (pair terms `<x.1, x.2>` in the signature view)
//!   `"` -> `&quot;`  (loaded-from path, and lemma text in the edit form)
//!   `&` -> `&amp;`   (a literal `&` inside a lemma formula)

/// Escape a plain string into HTML text, matching the web layer's entity set.
pub fn html_escape(s: &str) -> String {
    let mut out = String::with_capacity(s.len());
    for c in s.chars() {
        match c {
            '&' => out.push_str("&amp;"),
            '<' => out.push_str("&lt;"),
            '>' => out.push_str("&gt;"),
            '"' => out.push_str("&quot;"),
            '\'' => out.push_str("&#39;"),
            other => out.push(other),
        }
    }
    out
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn escapes_the_five_special_characters() {
        assert_eq!(html_escape("a<b>c"), "a&lt;b&gt;c");
        assert_eq!(html_escape("x & y"), "x &amp; y");
        assert_eq!(html_escape("say \"hi\""), "say &quot;hi&quot;");
        assert_eq!(html_escape("'smart'"), "&#39;smart&#39;");
    }

    #[test]
    fn passes_through_non_ascii_unchanged() {
        // Prover-emitted logic operators are not part of the escape set.
        assert_eq!(html_escape("∃ x ▶₀ #i"), "∃ x ▶₀ #i");
    }

    #[test]
    fn does_not_double_escape() {
        assert_eq!(html_escape("<&>"), "&lt;&amp;&gt;");
    }
}

//! JSON response envelopes for the `main/*` (and `method/*`, `autoprove/*`)
//! AJAX handlers.
//!
//! Observed: every `kind=json` response body is one of exactly two compact
//! JSON objects, with keys in this order and no insignificant whitespace:
//!   * content:  `{"html":<string>,"title":<string>}`
//!   * redirect: `{"redirect":<string>}`
//! There is no trailing newline. Non-ASCII is emitted as literal UTF-8 (no
//! `\uXXXX`), and `/ < > &` are NOT backslash/entity escaped inside the JSON
//! string — i.e. standard JSON string escaping (only `" \` and control chars).
//! `serde_json`'s default serialization reproduces this exactly.

use serde::Serialize;

/// A content pane response: rendered HTML plus the pane title.
#[derive(Serialize)]
pub struct Content<'a> {
    pub html: &'a str,
    pub title: &'a str,
}

/// A redirect response instructing the client to navigate to `redirect`.
#[derive(Serialize)]
pub struct Redirect<'a> {
    pub redirect: &'a str,
}

/// Serialize `{"html":..,"title":..}` exactly as the web layer does.
pub fn render_content(html: &str, title: &str) -> String {
    serde_json::to_string(&Content { html, title }).expect("Content serializes")
}

/// Serialize `{"redirect":..}` exactly as the web layer does.
pub fn render_redirect(path: &str) -> String {
    serde_json::to_string(&Redirect { redirect: path }).expect("Redirect serializes")
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn content_envelope_shape() {
        assert_eq!(
            render_content("this is a mistake<br/>\n", "Lemma: exec"),
            r#"{"html":"this is a mistake<br/>\n","title":"Lemma: exec"}"#
        );
    }

    #[test]
    fn redirect_envelope_shape() {
        assert_eq!(
            render_redirect("/thy/trace/4/overview/proof/exec/_"),
            r#"{"redirect":"/thy/trace/4/overview/proof/exec/_"}"#
        );
    }

    #[test]
    fn keeps_literal_utf8_and_unescaped_angle_brackets() {
        let s = render_content("<span>∃</span>", "t");
        assert!(s.contains("<span>∃</span>"), "got {s}");
        assert!(!s.contains("\\u"), "should not \\u-escape: {s}");
    }
}

//! The full-page theory-view HTML shell returned by the `overview/*` routes.
//!
//! Observed structure (constant across theories after substituting the four
//! parameters below): a fixed `<head>` of stylesheet/script links, a north
//! header bar, then four layout panes — west "Proof scripts", east "Debug
//! information" (always empty), and center "Visualization display". The west
//! pane embeds the proof-script markup (see [`crate::proofscript`]); the center
//! pane embeds the currently-selected main content HTML (the same HTML the
//! corresponding `main/*` route returns in its JSON `html` field).
//!
//! Scaffolding constants in `shell_template` are byte-exact copies of oracle
//! output with four `§`-delimited slots: NAME, IDX, VERSION, FILENAME. The
//! body has no trailing newline (ends `</html>`). All internal links use the
//! resolved numeric theory index, never `#`.

use crate::escape::html_escape;
use crate::shell_template::{PAGE_MID, PAGE_PREFIX, PAGE_TAIL};

/// Parameters that vary between rendered pages.
pub struct PageParams<'a> {
    /// Theory name, shown in `<title>Theory: NAME</title>`.
    pub theory_name: &'a str,
    /// Resolved numeric theory index used in every internal URL.
    pub index: u64,
    /// Tamarin version string shown in the header (e.g. `"1.13.0"`).
    pub version: &'a str,
    /// Source filename used in the download / append links (e.g. `"foo.spthy"`).
    pub filename: &'a str,
}

/// Render the full theory-view page from the shell parameters plus the already
/// rendered west (proof-script) and center (main content) pane inner HTML.
pub fn render_page(p: &PageParams, west_inner: &str, center_inner: &str) -> String {
    let idx = p.index.to_string();
    let prefix = PAGE_PREFIX
        .replace("§NAME§", &html_escape(p.theory_name))
        .replace("§IDX§", &idx)
        .replace("§VERSION§", p.version)
        .replace("§FILENAME§", p.filename);
    let mut out = String::with_capacity(
        prefix.len() + west_inner.len() + PAGE_MID.len() + center_inner.len() + PAGE_TAIL.len(),
    );
    out.push_str(&prefix);
    out.push_str(west_inner);
    out.push_str(PAGE_MID);
    out.push_str(center_inner);
    out.push_str(PAGE_TAIL);
    out
}

//! The proof-script (west) pane markup embedded in the theory-view page and in
//! the `main/*` navigation.
//!
//! ## Line model (observed)
//! The pane is a flat sequence of logical lines. Rendering emits each line's
//! text followed by the literal `"<br/>\n"`, and finally a single trailing
//! space `" "`. A blank line is an element whose text is empty (yielding a lone
//! `"<br/>\n"`). This one rule reproduces the exact blank-line spacing of both
//! the no-lemma and multi-lemma captures.
//!
//! ## Element order
//! 1. `theory NAME begin` header line
//! 2. one blank + link line per theory item, in order: Message theory, rules,
//!    Tactic(s), Raw sources, Refined sources
//! 3. one blank + the `add lemma` link for position `<first>`
//! 4. for each lemma: one blank, the lemma's body lines, one blank, the lemma's
//!    trailing `add lemma` link (targeting that lemma's name)
//! 5. one blank + `end`
//!
//! When there are zero lemmas, step 4 contributes nothing, which leaves TWO
//! blank lines between the `<first>` add-link and `end` (matching the capture).
//!
//! ## Slots that come from the prover (opaque here)
//! The lemma declaration HTML (`decl_html`: the pretty-printed `lemma NAME:` +
//! quantifier + formula, already entity-escaped and wrapped in `hl_operator`
//! spans), the rules label/count, the sources descriptions, and — for a solved
//! proof — each proof step's method HTML and case names. Everything else (the
//! anchors, keywords, indentation, links) is generated here.
//!
//! ## Indices
//! Every internal href uses the resolved numeric theory index, never `#`.

use std::fmt::Write;

/// A theory item shown as a top link in the proof-script pane.
pub enum Item<'a> {
    /// `Message theory` link.
    Message,
    /// Multiset rewriting rules link. `label` is the prover's wording
    /// (`"Multiset rewriting rules"`, or with `" and restrictions"`), `count`
    /// the rule count.
    Rules { label: &'a str, count: usize },
    /// `Tactic(s)` link.
    Tactic,
    /// `Raw sources` link; `desc` e.g. `"4 cases, deconstructions complete"`.
    RawSources { desc: &'a str },
    /// `Refined sources` link; note the label carries a trailing space.
    RefinedSources { desc: &'a str },
}

/// How a lemma's proof is displayed.
pub enum Proof<'a> {
    /// Unproven: a single `by sorry` proof-step line.
    Sorry,
    /// A solved/partial proof rendered as an explicit list of proof lines.
    Steps(Vec<ProofLine<'a>>),
}

/// One line of a rendered proof tree.
pub enum ProofLine<'a> {
    /// A proof-method step (an applied method or a leaf such as `SOLVED`).
    Step {
        depth: usize,
        /// Status class, e.g. `"hl_good"`.
        status: &'a str,
        /// Full href, e.g. `/thy/trace/3/main/proof/exec/_/B_2`.
        href: String,
        /// Prover method HTML, e.g. `<span class="hl_keyword">simplify</span>`.
        method_html: &'a str,
        /// Annotation shown in the remove-step anchor (usually empty).
        annotation: &'a str,
        /// Whether the line is prefixed with a wrapped `by ` keyword.
        by: bool,
    },
    /// A `case NAME` header.
    Case {
        depth: usize,
        status: &'a str,
        name: &'a str,
    },
    /// A `next` separator between sibling cases.
    Next { depth: usize, status: &'a str },
    /// A `qed` closing a case block.
    Qed { depth: usize, status: &'a str },
}

/// A single lemma block.
pub struct Lemma<'a> {
    /// Lemma name (used in the edit/delete/add/proof links).
    pub name: &'a str,
    /// Opaque prover-produced declaration HTML (`lemma NAME:` + formula).
    pub decl_html: &'a str,
    /// Proof display.
    pub proof: Proof<'a>,
}

/// The whole proof-script pane input.
pub struct Overview<'a> {
    pub theory_name: &'a str,
    pub index: u64,
    pub items: Vec<Item<'a>>,
    pub lemmas: Vec<Lemma<'a>>,
}

fn indent(depth: usize) -> String {
    "&nbsp;&nbsp;".repeat(depth)
}

/// Render one proof-tree line (public so the line grammar can be unit-tested).
pub fn render_proof_line(line: &ProofLine) -> String {
    match line {
        ProofLine::Step {
            depth,
            status,
            href,
            method_html,
            annotation,
            by,
        } => {
            let ind = indent(*depth);
            let by_prefix = if *by {
                format!(r#"<span class="{status}"><span class="hl_keyword">by</span> </span>"#)
            } else {
                String::new()
            };
            format!(
                r#"{ind}{by_prefix}<a class="internal-link proof-step {status}" href="{href}">{method_html}</a><a class="internal-link remove-step" href="{href}">{annotation}</a>"#
            )
        }
        ProofLine::Case {
            depth,
            status,
            name,
        } => format!(
            r#"{}<span class="{status}"><span class="hl_keyword">case</span> {name}</span>"#,
            indent(*depth)
        ),
        ProofLine::Next { depth, status } => format!(
            r#"{}<span class="{status}"><span class="hl_keyword">next</span></span>"#,
            indent(*depth)
        ),
        ProofLine::Qed { depth, status } => format!(
            r#"{}<span class="{status}"><span class="hl_keyword">qed</span></span>"#,
            indent(*depth)
        ),
    }
}

fn item_line(item: &Item, idx: u64) -> String {
    match item {
        Item::Message => format!(
            r#"<a class="internal-link" href="/thy/trace/{idx}/main/message"><strong>Message theory</strong> </a>"#
        ),
        Item::Rules { label, count } => format!(
            r#"<a class="internal-link" href="/thy/trace/{idx}/main/rules"><strong>{label}</strong> ({count})</a>"#
        ),
        Item::Tactic => format!(
            r#"<a class="internal-link" href="/thy/trace/{idx}/main/tactic"><strong>Tactic(s)</strong> </a>"#
        ),
        Item::RawSources { desc } => format!(
            r#"<a class="internal-link" href="/thy/trace/{idx}/main/cases/raw/0/0"><strong>Raw sources</strong> ({desc})</a>"#
        ),
        Item::RefinedSources { desc } => format!(
            r#"<a class="internal-link" href="/thy/trace/{idx}/main/cases/refined/0/0"><strong>Refined sources </strong> ({desc})</a>"#
        ),
    }
}

fn add_link(idx: u64, target: &str) -> String {
    format!(r#"<a class="internal-link add" href="/thy/trace/{idx}/main/add/{target}">add lemma</a>"#)
}

fn edit_delete_line(idx: u64, name: &str) -> String {
    format!(
        r#"<a class="internal-link edit" href="/thy/trace/{idx}/main/edit/{name}">edit lemma</a>  or  <a class="internal-link delete" href="/thy/trace/{idx}/main/delete/{name}">delete lemma</a>"#
    )
}

fn sorry_line(idx: u64, name: &str) -> String {
    format!(
        r#"<span class="hl_keyword">by</span> <a class="internal-link proof-step sorry-step" href="/thy/trace/{idx}/main/proof/{name}"><span class="hl_keyword">sorry</span></a>"#
    )
}

/// The theory header line: `theory NAME begin`.
fn header_line(name: &str, idx: u64) -> String {
    format!(
        r#"<span class="hl_keyword">theory</span> <a class="internal-link help" href="/thy/trace/{idx}/main/help">{name}</a> <span class="hl_keyword">begin</span>"#
    )
}

/// Render the full inner HTML of the `#proof` west pane.
pub fn render_proof_script(o: &Overview) -> String {
    let idx = o.index;
    // Build the flat element list.
    let mut elems: Vec<String> = Vec::new();
    elems.push(header_line(o.theory_name, idx));
    for item in &o.items {
        elems.push(String::new());
        elems.push(item_line(item, idx));
    }
    elems.push(String::new());
    elems.push(add_link(idx, "%3Cfirst%3E"));
    if o.lemmas.is_empty() {
        elems.push(String::new());
        elems.push(String::new());
    } else {
        for lemma in &o.lemmas {
            elems.push(String::new());
            elems.push(lemma.decl_html.to_string());
            elems.push(edit_delete_line(idx, lemma.name));
            match &lemma.proof {
                Proof::Sorry => elems.push(sorry_line(idx, lemma.name)),
                Proof::Steps(lines) => {
                    for l in lines {
                        elems.push(render_proof_line(l));
                    }
                }
            }
            elems.push(String::new());
            elems.push(add_link(idx, lemma.name));
        }
        elems.push(String::new());
    }
    elems.push(header_end());

    let mut out = String::new();
    for e in &elems {
        out.push_str(e);
        out.push_str("<br/>\n");
    }
    out.push(' ');
    let _ = write!(out, ""); // no-op; keeps `Write` import meaningful
    out
}

fn header_end() -> String {
    r#"<span class="hl_keyword">end</span>"#.to_string()
}

