    #[test]
    fn empty_graph_dot_shape() {
        assert!(EMPTY_GRAPH_DOT.starts_with("digraph \"G\" {\n"));
        assert!(EMPTY_GRAPH_DOT.ends_with("}\n"));
    }

    #[test]
    fn dotsrc_builder() {
        assert_eq!(
            dotsrc_path(3, "proof/exec"),
            "/thy/trace/3/interactive-graph-def/proof/exec"
        );
    }
}

